import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  CForm, CButton, CFormLabel, CFormCheck,
  CCard,
  CCardBody,
  CCardHeader,
  CCol,
  CModal,
  CModalBody,
  CModalFooter,
  CModalHeader,
  CModalTitle,
  CPopover,
  CRow,
  CTooltip
} from "@coreui/react";
import Select from "react-select";
import TagsInput from "react-tagsinput";
import "react-tagsinput/react-tagsinput.css";
import FormInput from 'src/utils/FormInput';
import UploadFiles from 'src/utils/UploadFiles';
import { getEnableCategory } from 'src/components/services/CategoryApi';
import TextArea from 'src/utils/TextArea';
import { v4 as uuidv4 } from 'uuid';
import { createInfograpic, getInfrograpicDataById, updateInfrograpic } from 'src/components/services/InfrograpicApi';
import { getRelatedTriviaByCategory } from 'src/components/services/TriviaApi';
import { getRelatedBlogByCategory } from 'src/components/services/BlogApi';
import GoBackComponent from 'src/utils/GoBackComponent';

const themeOptions = [
  { label: "Theme One", value: "THEME_ONE", isDisabled: true },
  { label: "Theme Two", value: "THEME_TWO" },
  { label: "Theme Three", value: "THEME_THREE" }
];

const InfrograpicForm = (props) => {
  const { type, id } = props;

  const [formData, setFormData] = useState({
    title: "",
    showNumber: true,
    metaTitle: "",
    metaDescription: "",
    metaImageAlt: ""
  });
  const [coverImage, setCoverImage] = useState("");
  const [tags, setTags] = useState([]);
  const [metaKeyWords, setMetaKeywords] = useState([]);
  const [theme, setTheme] = useState({});
  const [errors, setErrors] = useState({});
  const [category, setCategory] = useState({});
  const [infrograpicDetails, setInfrograpicDetails] = useState([
    { title: "", description: "", attachment: {}, _id: uuidv4() }
  ]);
  const [isButtonDisabled, setIsButtonDisabled] = useState(false);
  const [categoryOption, setCategoryOption] = useState([]);
  const [blogOption, setBlogOption] = useState([]);
  const [triviaOption, setTriviaOption] = useState([]);
  const [relatedBlog, setRelatedBlog] = useState([]);
  const [relatedTrivia, setRelatedTrivia] = useState([]);
    const [visible, setVisible] = useState(false)

  const navigate = useNavigate();

  const handleChange = (event) => {
    setFormData({ ...formData, [event.target.name]: event.target.value.trimStart().replace(/  +/g, ' ') });
  };

  const tagsChange = (tag) => {
    setTags(tag);
  };

  const metaTagsChange = (tag) => {
    setMetaKeywords(tag);
  };

  const uploadCoverImage = (image) => {
    setCoverImage(image);
  };

  const uploadImageData = (imagePath, logoFlag, id) => {
    const newState = infrograpicDetails.map(obj => {
      if (obj._id === id) {
        return { ...obj, ["attachment"]: imagePath };
      }
      return obj;
    });
    setInfrograpicDetails(newState);
  };

  const handleChangeCategory = (data, type) => {
    if (type === "THEME") {
      setTheme(data);
    } else if (type === "TRIVIA") {
      setRelatedTrivia(data);
    } else if (type === "BLOG") {
      setRelatedBlog(data);
    } else {
      setCategory(data);
      setRelatedBlog([]);
      setRelatedTrivia([]);
      setBlogOption([]);
      setTriviaOption([]);
      getBlogOptionData(data.value);
      getTriviaOptionData(data.value);
    }
  };

  const getTriviaOptionData = async (id, relatedTrivias) => {
    let response = await getRelatedTriviaByCategory(id);
    if (response?.code === 200) {
      response?.results && response?.results.map((data) => {
        setTriviaOption(current => [...current, { label: data.name, value: data.id }]);
      });
      if (type === "UPDATE") {
        var filteredArray = response?.results && response?.results.filter(function (n) { return relatedTrivias && relatedTrivias.indexOf(n.id) !== -1; });
        filteredArray && filteredArray.map((data) => { setRelatedTrivia(current => [...current, { label: data.name, value: data.id }]); });
      }
    }
  };

  const getBlogOptionData = async (id, relatedBlogs) => {
    let response = await getRelatedBlogByCategory(id);
    if (response?.code === 200) {
      response?.results && response?.results.map((data) => {
        setBlogOption(current => [...current, { label: data.name, value: data.id }]);
      });
      if (type === "UPDATE") {
        var filteredArray = response?.results && response?.results.filter(function (n) { return relatedBlogs && relatedBlogs.indexOf(n.id) !== -1; });
        filteredArray && filteredArray.map((data) => { setRelatedBlog(current => [...current, { label: data.name, value: data.id }]); });
      }
    }
  };

  const validateForm = () => {
    let errors = {};
    let formIsValid = true;
    if (!formData.title) {
      errors['title'] = "Please enter title";
      formIsValid = false;
    }
    if (!coverImage) {
      errors['coverImage'] = "Please add cover image";
      formIsValid = false;
    }
    if (!category?.value) {
      errors['category'] = "Please choose category";
      formIsValid = false;
    }
    if (!theme?.value) {
      errors['theme'] = "Please choose theme";
      formIsValid = false;
    }
    if (tags.length === 0) {
      errors['tags'] = "Please enter at least one tag";
      formIsValid = false;
    }
    if (!formData?.metaTitle) {
      errors['metaTitle'] = "Please enter meta title";
      formIsValid = false;
    }
    if (!formData?.metaDescription) {
      errors['metaDescription'] = "Please enter meta description";
      formIsValid = false;
    }
    if (!formData?.metaImageAlt) {
      errors['metaImageAlt'] = "Please enter meta image alt";
      formIsValid = false;
    }
    if (metaKeyWords.length === 0) {
      errors['metaKeyWords'] = "Please enter at least one meta keyword";
      formIsValid = false;
    }
    infrograpicDetails && infrograpicDetails.forEach((data, index) => {
      const newArray = infrograpicDetails;
      if (!data.title) {
        newArray[index].titleError = "Please enter title.";
        formIsValid = false;
      }
      if (!data.description) {
        newArray[index].descError = "Please enter description.";
        formIsValid = false;
      }
      if (!data?.attachment?.imageUrl && theme?.value === "THEME_THREE") {
        newArray[index].imgError = "Please select image.";
        formIsValid = false;
      }
      setInfrograpicDetails(newArray);
      setTimeout(() => {
        newArray[index].titleError = "";
        newArray[index].descError = "";
        newArray[index].imgError = "";
        setInfrograpicDetails(newArray);
      }, 2000);
    });
    setErrors(errors);
    setTimeout(() => {
      setErrors({});
    }, 2000);
    return formIsValid;
  };

  const fetchInfrograpicDataById = async (id, categories) => {
    let response = await getInfrograpicDataById(id);
    if (response?.code === 200 && response?.results != null) {
      let result = response?.results;
      let category = categories && categories.find((data) => data.value === result?.data?.category);
      let theme = themeOptions && themeOptions.find((data) => data.value === result?.data?.themeName);
      setFormData({
        ...formData,
        title: result?.data?.title,
        showNumber: result?.data?.showNumber,
        metaTitle: result?.data?.metaTitle,
        metaDescription: result?.data?.metaDescription,
        metaImageAlt: result?.data?.metaImageAlt
      });
      setCategory(category);
      setTheme(theme);
      setCoverImage(result?.coverImage);
      setInfrograpicDetails(result?.detailsAttachmentsList);
      setTags(result?.data?.tags);
      setMetaKeywords(result?.data?.metaKeyWords);
      getTriviaOptionData(result?.data?.category, result?.data?.relatedTrivias);
      getBlogOptionData(result?.data?.category, result?.data?.relatedBlogs);
    }
  };

  const handleSubmit = async (event) => {
    event.preventDefault();
    if (validateForm()) {
      let detailsList = [];
      let relatedBlogs = [];
      let relatedTrivias = [];
      infrograpicDetails && infrograpicDetails.forEach((data) => {
        detailsList.push({ title: data.title, description: data.description, imageUrl: data.attachment?._id });
      });
      relatedBlog && relatedBlog.forEach((item) => {
        relatedBlogs.push(item.value);
      });
      relatedTrivia && relatedTrivia.forEach((item) => {
        relatedTrivias.push(item.value);
      });
      let data = {
        title: formData?.title?.trim(),
        category: category?.value,
        coverImageUrl: coverImage?._id,
        themeName: theme?.value,
        tags: tags,
        details: detailsList,
        showNumber: formData?.showNumber,
        relatedBlogs: relatedBlogs,
        relatedTrivias: relatedTrivias,
        metaTitle: formData?.metaTitle,
        metaDescription: formData?.metaDescription,
        metaKeyWords: metaKeyWords,
        metaImageAlt: formData?.metaImageAlt
      };
      let infrograpic = {};
      if (type === "CREATE") {
        infrograpic = await createInfograpic(data);
      } else {
        infrograpic = await updateInfrograpic(props.id, data);
      }
      if (infrograpic?.code === 201 || infrograpic?.code === 202) {
        navigate('/infrograpic');
      }
    }
  };

  const getCategory = async () => {
    let categories = [];
    let response = await getEnableCategory();
    if (response?.code === 200) {
      response?.results && response?.results.map((data) => {
        categories.push({ label: data.name, value: data._id });
      });
      setCategoryOption(categories);
      if (props.type === "UPDATE") {
        fetchInfrograpicDataById(props.id, categories);
      }
    }
  };

  const addSection = () => {
    setInfrograpicDetails(current => [...current, { title: "", description: "", attachment: {}, _id: uuidv4() }]);
  };

  const deleteSection = (id) => {
    let index = infrograpicDetails.findIndex((data) => data._id === id);
    if (index > -1) {
      setInfrograpicDetails([
        ...infrograpicDetails.slice(0, index),
        ...infrograpicDetails.slice(index + 1)
      ]);
    }
  };

  const handleChangeVisibility = (event) => {
    setFormData({ ...formData, [event.target.name]: event.target.checked });
  };

  const handleChangeDetails = (event, id) => {
    const newState = infrograpicDetails.map(obj => {
      if (obj._id === id) {
        return { ...obj, [event.target.name]: event.target.value.trimStart().replace(/  +/g, ' ') };
      }
      return obj;
    });
    setInfrograpicDetails(newState);
  };

  const Preview = () => {
    console.log("theme", theme)
    return (
      <>
        <a href="javascript:void(0)" onClick={() => setVisible(!visible)}>Preview</a>
        <CModal visible={visible} onClose={() => setVisible(false)}>
          <CModalHeader>
            <CModalTitle>Theme preview</CModalTitle>
          </CModalHeader>
          <CModalBody>
            {theme.value === "THEME_TWO"  ? <img src="https://cdn.wseinfratech.com/Theme_2.png" style={{width:"100%", height:"auto"}}/> : <img src="https://cdn.wseinfratech.com/Theme_3.png" style={{width:"100%", height:"auto"}}/>}
          </CModalBody>
          <CModalFooter>
            <CButton color="secondary" onClick={() => setVisible(false)}>
              Close
            </CButton>
          </CModalFooter>
        </CModal>
      </>
    )
  }

  useEffect(() => {
    getCategory();
  }, []);

  return (
    <>
      <GoBackComponent goBackData={"infrograpic"} />
      <div className='customContainer'>
        <CForm className="row g-3">
          <UploadFiles
            id={"blogCoverImage"}
            accept=".jpg,.png,.jpeg"
            label="Cover Image"
            updateImage={coverImage?.imageUrl}
            updateFilesCb={uploadCoverImage}
          />
          <span style={{ color: "red", textAlign: "center" }}>{errors['coverImage']}</span>
          <CCol md={12}>
            <FormInput
              value={formData.title}
              label={"Title"}
              name={"title"}
              onChange={handleChange}
              required={true}
              error={errors['title']}
            />
          </CCol>
          <CCol md={6}>
            <div className='form-group'>
              <CFormLabel> Select Category <span className="text-danger">*</span></CFormLabel>
              <Select
                placeholder={"Select type"}
                className="wnforSelect"
                name={"categoryFilterOption"}
                options={categoryOption}
                value={category}
                onChange={(data) => handleChangeCategory(data, "CATEGORY")}
                classNamePrefix="select"
                styles={{
                    option: (styles, { data, isDisabled, isFocused, isSelected }) => {
                        const color = '#03a68059';
                        return {
                            ...styles,
                            backgroundColor: isDisabled
                                ? null
                                : isSelected
                                    ? '#03a68059'
                                    : isFocused
                                        ? '#03a68059'
                                        : null,
                            color: isDisabled
                                ? '#ccc'
                                : isSelected
                                    ? color > 2
                                        ? '#00374d'
                                        : '#00374d'
                                    : data.color,
                            cursor: isDisabled ? 'not-allowed' : 'default',

                            ':active': {
                                ...styles[':active'],
                                backgroundColor: !isDisabled && (isSelected ? '#03a68059' : '#03a68059'),
                            },
                        };
                    },
                }}
              />
              <span style={{ color: "red" }}>{errors['category']}</span>
            </div>
          </CCol>
          <CCol md={6}>
            <div className='form-group'>
              <CFormLabel> Select Theme <span className="text-danger">*</span> {Preview()}
              </CFormLabel>
              <Select
                placeholder={"Select type"}
                className="wnforSelect"
                name={"themeFilterOption"}
                options={themeOptions}
                value={theme}
                onChange={(data) => handleChangeCategory(data, "THEME")}
                classNamePrefix="select"
                styles={{
                    option: (styles, { data, isDisabled, isFocused, isSelected }) => {
                        const color = '#03a68059';
                        return {
                            ...styles,
                            backgroundColor: isDisabled
                                ? null
                                : isSelected
                                    ? '#03a68059'
                                    : isFocused
                                        ? '#03a68059'
                                        : null,
                            color: isDisabled
                                ? '#ccc'
                                : isSelected
                                    ? color > 2
                                        ? '#00374d'
                                        : '#00374d'
                                    : data.color,
                            cursor: isDisabled ? 'not-allowed' : 'default',

                            ':active': {
                                ...styles[':active'],
                                backgroundColor: !isDisabled && (isSelected ? '#03a68059' : '#03a68059'),
                            },
                        };
                    },
                }}
              />
              <span style={{ color: "red" }}>{errors['theme']}</span>
            </div>
          </CCol>
          <CFormLabel> Details Section <span className="text-danger">*</span></CFormLabel>
          {infrograpicDetails.map((data, index) => {
            return (
              <React.Fragment key={data._id}>
                <CCol md={8}>
                  <FormInput
                    value={data.title}
                    label={"Title"}
                    name={"title"}
                    onChange={(e) => handleChangeDetails(e, data._id)}
                    required={true}
                    error={data.titleError}
                  />
                  <div className='form-group'>
                    <TextArea
                      label={"Description"}
                      name={"description"}
                      value={data.description}
                      onChange={(e) => handleChangeDetails(e, data._id)}
                      required={true}
                      error={data.descError}
                    />
                  </div>
                </CCol>
                <CCol md={4}>
                  <UploadFiles
                    id={"detailsImage" + data._id}
                    accept=".jpg,.png,.jpeg"
                    label="Image"
                    updateImage={data.attachment?.imageUrl}
                    updateFilesCb={uploadImageData}
                    uploadFileId={data._id}
                    logoUploadFiles={true}
                  />
                  <span style={{ color: "red", textAlign: "center" }}>{data.imgError}</span>
                </CCol>
                {index > 0 && (
                  <CCol md={12}>
                    <CButton color="danger" onClick={() => deleteSection(data._id)} className="d-block">
                      Delete Section
                    </CButton>
                  </CCol>
                )}
                <hr />
              </React.Fragment>
            );
          })}
          <CCol md={12}>
            <CButton color="primary" onClick={addSection} className="d-block">
              Add Section
            </CButton>
          </CCol>
          <CCol md={6}>
            <CFormCheck
              id="showNumber"
              name={"showNumber"}
              label="Show Number"
              onClick={handleChangeVisibility}
              checked={formData?.showNumber}
            />
          </CCol>
          <CCol md={12}>
            <CFormLabel> Tags <span className="text-danger">*</span></CFormLabel>
            <TagsInput
              value={tags}
              onChange={tagsChange}
              addKeys={[9, 13, 62, 188]}
            />
            <span style={{ color: "red" }}>{errors['tags']}</span>
          </CCol>
          <CCol md={12}>
            <div className='form-group'>
              <CFormLabel> Select Related Blog</CFormLabel>
              <Select
                placeholder={"Select Related Blog"}
                className="wnforSelect"
                name={"blogFilterOption"}
                options={blogOption}
                value={relatedBlog}
                isMulti
                onChange={(data) => handleChangeCategory(data, "BLOG")}
                classNamePrefix="select"
                styles={{
                    option: (styles, { data, isDisabled, isFocused, isSelected }) => {
                        const color = '#03a68059';
                        return {
                            ...styles,
                            backgroundColor: isDisabled
                                ? null
                                : isSelected
                                    ? '#03a68059'
                                    : isFocused
                                        ? '#03a68059'
                                        : null,
                            color: isDisabled
                                ? '#ccc'
                                : isSelected
                                    ? color > 2
                                        ? '#00374d'
                                        : '#00374d'
                                    : data.color,
                            cursor: isDisabled ? 'not-allowed' : 'default',

                            ':active': {
                                ...styles[':active'],
                                backgroundColor: !isDisabled && (isSelected ? '#03a68059' : '#03a68059'),
                            },
                        };
                    },
                }}
              />
            </div>
          </CCol>
          <CCol md={12}>
            <div className='form-group'>
              <CFormLabel> Select Related Trivia</CFormLabel>
              <Select
                placeholder={"Select Related Trivia"}
                className="wnforSelect"
                name={"triviaFilterOption"}
                options={triviaOption}
                value={relatedTrivia}
                isMulti
                onChange={(data) => handleChangeCategory(data, "TRIVIA")}
                classNamePrefix="select"
                styles={{
                    option: (styles, { data, isDisabled, isFocused, isSelected }) => {
                        const color = '#03a68059';
                        return {
                            ...styles,
                            backgroundColor: isDisabled
                                ? null
                                : isSelected
                                    ? '#03a68059'
                                    : isFocused
                                        ? '#03a68059'
                                        : null,
                            color: isDisabled
                                ? '#ccc'
                                : isSelected
                                    ? color > 2
                                        ? '#00374d'
                                        : '#00374d'
                                    : data.color,
                            cursor: isDisabled ? 'not-allowed' : 'default',

                            ':active': {
                                ...styles[':active'],
                                backgroundColor: !isDisabled && (isSelected ? '#03a68059' : '#03a68059'),
                            },
                        };
                    },
                }}
              />
            </div>
          </CCol>

          <hr />

          <CCol md={12}>
            <FormInput
              value={formData.metaTitle}
              label={"Meta Title"}
              name={"metaTitle"}
              onChange={handleChange}
              required={true}
              error={errors['metaTitle']}
            />
          </CCol>

          <CCol md={12}>
            <TextArea
              label={"Meta Description"}
              name="metaDescription"
              value={formData.metaDescription}
              onChange={handleChange}
              required={true}
              error={errors["metaDescription"]}
            />
          </CCol>

          <CCol md={12}>
            <TextArea
              label={"Meta Image Alt"}
              name="metaImageAlt"
              value={formData.metaImageAlt}
              onChange={handleChange}
              required={true}
              error={errors["metaImageAlt"]}
            />
          </CCol>

          <CCol md={12}>
            <CFormLabel>Meta Keywords <span className="text-danger">*</span></CFormLabel>
            <TagsInput
              value={metaKeyWords}
              onChange={metaTagsChange}
              addKeys={[9, 13, 62, 188]}
            />
            <span style={{ color: "red" }}>{errors['metaKeyWords']}</span>
          </CCol>

          <CCol md={12}>
            <CButton color="primary" onClick={handleSubmit} className="d-block" disabled={isButtonDisabled}>
              {type === "CREATE" ? "Create" : "Update"}
            </CButton>
          </CCol>
        </CForm>
      </div>
    </>
  );
};

export default InfrograpicForm;
